use god_gragh::tensor::differentiable::DifferentiableGraph;

// 1. 从标准 Transformer 构建可微图
let mut diff_graph = DifferentiableGraph::from_transformer(&model);

// 2. 定义目标函数（注意力熵 + 稀疏性正则）
let loss_fn = |g: &DifferentiableGraph| {
    g.entropy_loss() + 0.1 * g.sparsity_loss()
};

// 3. 梯度下降优化结构
for step in 0..100 {
    let loss = loss_fn(&diff_graph);
    let grads = diff_graph.compute_structure_gradients(loss);
    diff_graph.update_structure(&grads, lr=0.01);
}

// 4. 导出剪枝后的图
let pruned_graph = diff_graph.discretize(threshold=0.5);
println!("剪枝了 {} 条弱注意力边", pruned_graph.num_pruned_edges());

