//! 示例：用梯度下降优化注意力结构
//!
//! 这个示例展示如何用 DifferentiableGraph 实现动态注意力剪枝：
//! 1. 从标准 Transformer 构建可微图
//! 2. 定义目标函数（注意力熵 + 稀疏性正则）
//! 3. 梯度下降优化边结构
//! 4. 离散化并导出剪枝后的图

use god_gragh::graph::Graph;
use god_gragh::tensor::differentiable::{DifferentiableGraph, GradientConfig, ThresholdEditPolicy};
use god_gragh::tensor::DenseTensor;

fn main() {
    // 1. 构建小型 Transformer 图
    let mut graph = build_mini_transformer();

    // 2. 转换为可微图（边权重变为可学习参数）
    let config = GradientConfig::default()
        .with_sparsity(0.1); // L1 稀疏正则
    let mut diff_graph = DifferentiableGraph::from_graph(graph, config);

    // 3. 梯度下降优化结构
    println!("开始优化注意力结构...");
    for step in 0..100 {
        // 计算目标函数：注意力熵（鼓励聚焦）+ 稀疏性（鼓励剪枝）
        let entropy_loss = diff_graph.entropy_loss();
        let sparsity_loss = diff_graph.sparsity_loss();
        let total_loss = entropy_loss + sparsity_loss;

        // 计算梯度
        let grads = diff_graph.compute_structure_gradients(total_loss);

        // 更新结构
        diff_graph.update_structure(&grads, 0.01);

        if step % 10 == 0 {
            println!("Step {}: loss={:.4}, entropy={:.4}, sparsity={:.4}",
                step, total_loss, entropy_loss, sparsity_loss);
        }
    }

    // 4. 离散化（阈值=0.5）
    let policy = ThresholdEditPolicy::new(0.5);
    let pruned_graph = diff_graph.discretize(&policy);

    println!("\n优化完成!");
    println!("  原始边数：{}", graph.edge_count());
    println!("  剪枝后边数：{}", pruned_graph.edge_count());
    println!("  剪枝比例：{:.2}%", 
        (1.0 - pruned_graph.edge_count() as f64 / graph.edge_count() as f64) * 100.0);
}

fn build_mini_transformer() -> Graph<Vec<f64>, f64> {
    use god_gragh::graph::traits::GraphOps;

    let mut graph = Graph::directed();

    // 创建 token 节点
    let n_tokens = 4;
    let hidden_dim = 8;
    let mut token_nodes = Vec::new();

    for i in 0..n_tokens {
        let feature = vec![1.0; hidden_dim];
        let node_idx = graph.add_node(feature).unwrap();
        token_nodes.push(node_idx);
    }

    // 创建全连接注意力边（后续可剪枝）
    for &src in &token_nodes {
        for &dst in &token_nodes {
            if src != dst {
                let weight = 1.0 / (n_tokens - 1) as f64;
                let _ = graph.add_edge(src, dst, weight);
            }
        }
    }

    graph
}

