/// 统一图结构：同时支持结构梯度和参数梯度
///
/// 核心设计：利用 God-Graph 的桶式邻接表 + Generation 索引
/// - 结构参数（边存在性）存储在 EdgeData.logits
/// - 权重参数（W 矩阵）存储在 EdgeData.weight
/// - ComputeGraph 记录操作，支持自动微分
///
/// # 与 petgraph 的对比
///
/// petgraph 的边是静态的，删除边后索引失效。
/// God-Graph 的桶式邻接表 + Generation 索引：
/// - 删除边后，索引可安全重用（generation 检查）
/// - O(1) 增量更新（优于 CSR 格式）
/// - 支持动态结构优化（DifferentiableGraph 的核心需求）
pub struct UnifiedGraph {
    /// 主图结构（桶式邻接表）
    graph: Graph<NodeData, EdgeData>,
    /// 计算图（记录操作，支持 autograd）
    compute_graph: ComputeGraph,
    /// 结构梯度配置
    gradient_config: GradientConfig,
}

impl UnifiedGraph {
    /// 联合优化一步：同时更新结构和参数
    pub fn joint_optimization_step(
        &mut self,
        loss: &DenseTensor,
        structure_lr: f64,
        param_lr: f64,
    ) -> GraphResult<()> {
        // 1. 反向传播计算参数梯度
        let loss_id = self.compute_graph.get_loss_tensor_id(loss);
        let param_grads = self.compute_graph.backward(loss_id);

        // 2. 计算结构梯度（STE）
        let structure_grads = self.compute_structure_gradients(loss)?;

        // 3. 更新权重参数
        self.update_weights(&param_grads, param_lr)?;

        // 4. 更新结构参数（logits）
        self.update_structure(&structure_grads, structure_lr)?;

        // 5. 离散化弱边（利用桶式邻接表的 O(1) 删除）
        self.prune_weak_edges()?;

        Ok(())
    }
}

