/// 动态稀疏注意力：利用 God-Graph 的桶式邻接表实现 O(1) 编辑
///
/// # 与 FlashAttention 的对比
///
/// | 特性 | FlashAttention | DynamicSparseAttention |
/// |------|---------------|------------------------|
/// | 稀疏模式 | 静态（编译时确定） | 动态（运行时编辑） |
/// | 编辑开销 | O(n) 重建 CSR | O(1) 桶式邻接表 |
/// | GPU 支持 | ✅ | ✅ (CandleBackend) |
/// | 长程连接 | ❌ | ✅ (add_skip_connection) |
///
/// # 核心优势
///
/// 1. **动态剪枝**：基于注意力分数动态删除弱边
/// 2. **架构搜索**：梯度下降学习最优稀疏模式
/// 3. **长程连接**：运行时添加自定义连接
/// 4. **可视化**：导出 DOT 格式，直观理解注意力模式
pub struct DynamicSparseAttention {
    /// 注意力图（桶式邻接表）
    graph: Graph<AttentionNode, AttentionEdge>,
    /// 计算后端（CPU/GPU）
    backend: Box<dyn TensorBackend>,
    /// 稀疏性目标（用于梯度优化）
    sparsity_target: f64,
}

impl DynamicSparseAttention {
    /// 动态剪枝弱注意力边
    pub fn prune_weak_edges(&mut self, threshold: f64) -> usize {
        use crate::graph::traits::GraphQuery;

        let mut pruned = 0;
        let edge_indices: Vec<_> = self.graph.edges().map(|e| e.index()).collect();

        for edge_idx in edge_indices {
            let edge = &self.graph[edge_idx];
            if edge.attention_score < threshold {
                // O(1) 删除：桶式邻接表的优势
                let _ = self.graph.remove_edge(edge_idx);
                pruned += 1;
            }
        }

        pruned
    }

    /// 添加自定义长程连接
    pub fn add_skip_connection(&mut self, src: usize, dst: usize) {
        // O(1) 添加：桶式邻接表的优势
        let _ = self.graph.add_edge(
            NodeIndex::new(src, 0),
            NodeIndex::new(dst, 0),
            AttentionEdge::new_skip_connection(),
        );
    }
}
